<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --border: #30363d;
    --accent: #58e6a8;
    --accent2: #7c6cff;
    --text: #e6edf3;
    --muted: #8b949e;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: radial-gradient(ellipse at 50% -20%, #1a2332 0%, var(--bg) 60%);
    color: var(--text);
    font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 18px;
    padding: 24px;
  }
  h1 {
    margin: 0;
    font-size: 1.5rem;
    font-weight: 600;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    background: linear-gradient(90deg, var(--accent), var(--accent2));
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
  }
  #life {
    width: 520px;
    height: 520px;
    max-width: 92vw;
    max-height: 92vw;
    border: 1px solid var(--border);
    border-radius: 10px;
    background: #0a0e14;
    box-shadow: 0 0 40px rgba(88, 230, 168, 0.10), 0 8px 30px rgba(0,0,0,0.5);
    cursor: crosshair;
    touch-action: none;
    image-rendering: pixelated;
  }
  .controls {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    font: inherit;
    font-size: 0.95rem;
    padding: 9px 20px;
    border-radius: 999px;
    border: 1px solid var(--border);
    background: var(--panel);
    color: var(--text);
    cursor: pointer;
    transition: transform 0.1s ease, border-color 0.15s ease, box-shadow 0.15s ease;
  }
  button:hover {
    border-color: var(--accent);
    box-shadow: 0 0 12px rgba(88, 230, 168, 0.25);
    transform: translateY(-1px);
  }
  button:active { transform: translateY(1px) scale(0.97); }
  #play.running {
    background: linear-gradient(90deg, #1c3b2e, #232045);
    border-color: var(--accent);
    box-shadow: 0 0 16px rgba(88, 230, 168, 0.35);
  }
  .stats { color: var(--muted); font-size: 0.85rem; letter-spacing: 0.05em; }
  .hint { color: var(--muted); font-size: 0.8rem; }
</style>
</head>
<body>
  <h1>Game of Life</h1>
  <canvas id="life" width="520" height="520"></canvas>
  <div class="controls">
    <button id="step">⏭ Step</button>
    <button id="play">▶ Play</button>
    <button id="random">🎲 Random</button>
    <button id="clear">🧹 Clear</button>
  </div>
  <div class="stats"><span id="gen">gen 0</span> · <span id="pop">0 alive</span></div>
  <div class="hint">click or drag on the grid to paint cells</div>

<script>
(function () {
  "use strict";

  var W = 52, H = 52;          // cells (>= 40 each)
  var CELL = 10;               // device pixels per cell (canvas is 520x520)
  var canvas = document.getElementById("life");
  var ctx = canvas.getContext("2d");

  var grid = new Uint8Array(W * H);
  var next = new Uint8Array(W * H);
  var age  = new Uint8Array(W * H);   // for pretty colors only
  var generation = 0;

  function idx(x, y) { return y * W + x; }

  function get(x, y) {
    x = Math.floor(x); y = Math.floor(y);
    if (x < 0 || y < 0 || x >= W || y >= H) return 0;
    return grid[idx(x, y)];
  }

  function set(x, y, v) {
    x = Math.floor(x); y = Math.floor(y);
    if (x < 0 || y < 0 || x >= W || y >= H) return;
    grid[idx(x, y)] = v ? 1 : 0;
    if (!v) age[idx(x, y)] = 0;
    draw();
  }

  function step() {
    // Compute the entire next generation from the CURRENT grid,
    // then swap — a simultaneous update (B3/S23, dead edges).
    for (var y = 0; y < H; y++) {
      for (var x = 0; x < W; x++) {
        var n = 0;
        for (var dy = -1; dy <= 1; dy++) {
          for (var dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            var nx = x + dx, ny = y + dy;
            if (nx >= 0 && ny >= 0 && nx < W && ny < H) n += grid[idx(nx, ny)];
          }
        }
        var alive = grid[idx(x, y)];
        var willLive = alive ? (n === 2 || n === 3) : (n === 3);
        next[idx(x, y)] = willLive ? 1 : 0;
        age[idx(x, y)] = willLive ? Math.min(255, (alive ? age[idx(x, y)] : 0) + 1) : 0;
      }
    }
    var tmp = grid; grid = next; next = tmp;
    generation++;
    draw();
  }

  function clear() {
    grid.fill(0);
    age.fill(0);
    generation = 0;
    draw();
  }

  function randomize() {
    for (var i = 0; i < grid.length; i++) {
      grid[i] = Math.random() < 0.28 ? 1 : 0;
      age[i] = 0;
    }
    generation = 0;
    draw();
  }

  function cellColor(a) {
    // newborns glow green, elders shift toward violet
    var t = Math.min(a, 12) / 12;
    var r = Math.round(88 + t * (124 - 88));
    var g = Math.round(230 - t * (230 - 108));
    var b = Math.round(168 + t * (255 - 168));
    return "rgb(" + r + "," + g + "," + b + ")";
  }

  function draw() {
    ctx.fillStyle = "#0a0e14";
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // faint grid lines
    ctx.strokeStyle = "rgba(139,148,158,0.08)";
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (var gx = 0; gx <= W; gx++) {
      ctx.moveTo(gx * CELL + 0.5, 0); ctx.lineTo(gx * CELL + 0.5, H * CELL);
    }
    for (var gy = 0; gy <= H; gy++) {
      ctx.moveTo(0, gy * CELL + 0.5); ctx.lineTo(W * CELL, gy * CELL + 0.5);
    }
    ctx.stroke();

    var pop = 0;
    for (var y = 0; y < H; y++) {
      for (var x = 0; x < W; x++) {
        if (grid[idx(x, y)]) {
          pop++;
          ctx.fillStyle = cellColor(age[idx(x, y)]);
          ctx.fillRect(x * CELL + 1, y * CELL + 1, CELL - 2, CELL - 2);
        }
      }
    }
    document.getElementById("gen").textContent = "gen " + generation;
    document.getElementById("pop").textContent = pop + " alive";
  }

  // ---- painting (click / drag toggles cells) ----
  var painting = false;
  var paintValue = 1;

  function eventCell(e) {
    var rect = canvas.getBoundingClientRect();
    var x = Math.floor((e.clientX - rect.left) / rect.width * W);
    var y = Math.floor((e.clientY - rect.top) / rect.height * H);
    return { x: x, y: y };
  }

  canvas.addEventListener("pointerdown", function (e) {
    e.preventDefault();
    canvas.setPointerCapture(e.pointerId);
    painting = true;
    var c = eventCell(e);
    paintValue = get(c.x, c.y) ? 0 : 1;   // toggle: drag paints the opposite state
    set(c.x, c.y, paintValue);
  });

  canvas.addEventListener("pointermove", function (e) {
    if (!painting) return;
    var c = eventCell(e);
    if (get(c.x, c.y) !== paintValue) set(c.x, c.y, paintValue);
  });

  window.addEventListener("pointerup", function () { painting = false; });

  // ---- controls ----
  var playBtn = document.getElementById("play");
  var timer = null;

  function stopRun() {
    if (timer !== null) { clearInterval(timer); timer = null; }
    playBtn.textContent = "▶ Play";
    playBtn.classList.remove("running");
  }

  function startRun() {
    if (timer !== null) return;
    timer = setInterval(step, 90);
    playBtn.textContent = "⏸ Pause";
    playBtn.classList.add("running");
  }

  document.getElementById("step").addEventListener("click", function () {
    stopRun();
    step();
  });

  playBtn.addEventListener("click", function () {
    if (timer === null) startRun(); else stopRun();
  });

  document.getElementById("random").addEventListener("click", randomize);
  document.getElementById("clear").addEventListener("click", function () {
    stopRun();
    clear();
  });

  // ---- public API ----
  window.life = {
    w: W,
    h: H,
    get: get,
    set: set,
    step: step,
    clear: clear
  };

  // seed something fun: a glider plus a few blinkers
  clear();
  [[2,1],[3,2],[1,3],[2,3],[3,3]].forEach(function (p) { grid[idx(p[0], p[1])] = 1; });
  [[20,10],[21,10],[22,10], [30,30],[30,31],[30,32], [12,40],[13,40],[14,40]]
    .forEach(function (p) { grid[idx(p[0], p[1])] = 1; });
  draw();
})();
</script>
</body>
</html>
